export const playAlertSound = () => {
  try {
    // A clean "notification" beep
    const audio = new Audio('data:audio/wav;base64,' || 'sounds/click.mp3');
    audio.volume = 0.5;
    audio.play().catch(() => {});
  } catch (e) {}
};

export const playPageSound = () => {
  try {
    const audio = new Audio('data:audio/wav;base64,');
    audio.volume = 0.3;
    audio.play().catch(() => {});
  } catch (e) {}
};
